import strawberry
from typing import Optional
from models.product import Product as ProductModel
from database import db_session


@strawberry.type
class Product:
    id: int
    name: str
    price: float
    category: str


@strawberry.type
class Query:
    @strawberry.field
    def products(self, category: Optional[str] = None, limit: int = 20) -> list[Product]:
        query = db_session.query(ProductModel)
        if category:
            query = query.filter(ProductModel.category == category)
        rows = query.limit(limit).all()
        return [Product(id=r.id, name=r.name, price=r.price, category=r.category) for r in rows]

    @strawberry.field
    def product(self, id: int) -> Optional[Product]:
        r = db_session.query(ProductModel).get(id)
        if not r:
            return None
        return Product(id=r.id, name=r.name, price=r.price, category=r.category)


schema = strawberry.Schema(query=Query)
